import{_ as a,o as t,c as p,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"线稿盔甲","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/3.防具/5.A级/线稿盔甲.md","filePath":"4.资源分区/7.物品与装备/3.防具/5.A级/线稿盔甲.md"}'),o={name:"4.资源分区/7.物品与装备/3.防具/5.A级/线稿盔甲.md"};function d(b,e,l,_,i,c){return t(),p("div",null,[...e[0]||(e[0]=[r("h1",{id:"线稿盔甲",tabindex:"-1"},[n("线稿盔甲 "),r("a",{class:"header-anchor",href:"#线稿盔甲","aria-label":'Permalink to "线稿盔甲"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌039")])])],-1),s('<h1 id="线稿盔甲-1" tabindex="-1">线稿盔甲 <a class="header-anchor" href="#线稿盔甲-1" aria-label="Permalink to &quot;线稿盔甲&quot;">​</a></h1><p>线稿盔甲<br> 特异本质<br> A+4000</p><p>护甲防御：26/26<br> 防御类型：盔甲防御<br> 护甲分类：轻甲<br> 额外具有基于护甲防御的2点附加成功</p><p>描述：<br> 这是一套常人难以控制的强大盔甲，想要具有具体角色形象的人更是难以掌控其线稿之力，<br> 而线稿这一抽象概念本身就对于故事内经历叙事的角色而言有着跨纬度级别的理解难度，<br> 若穿戴者的心智类传奇属性总和小于10，那么穿戴者会在穿戴上护甲的同时，受到S级命运来源的即死效果，表现上为你四散为一团扭曲，无法辨认的细线，随后消失。</p><p>这一本质导致其展现方式也极其抽象，任何直面一个活生生的人身体部分转化为狂乱飞舞的粗糙线条时，都会在短时间内因认知过载而难以理解现状，陷入短暂的混乱与僵直。这也是这件盔甲的初衷——以存在形式的根本性异常，来瓦解一切基于“现实”与“完成品”的攻击与逻辑。<br> 因为这件盔甲的反直觉运作形态，导致其他人难以确定穿戴者的本体所在，穿戴者视为拥有A级特异本质的弱反侦测效果，最低只能以此降低至模糊定位。且这个效果无法自主关闭。</p><p>除此之外，这些旋转扭动的线稿之间也会存在极大的、未被填充的空隙。这些空隙并非物理意义上的“孔洞”，而是“未被定义”的领域。<br> 任何穿过这些空隙的攻击，无论其能量、实体还是概念性打击，都会因“命中目标未被定义”而判定失效，无法造成任何伤害。<br> 但盔甲的核心逻辑会确保穿戴者的“生命线”与“行动线”始终连贯，从而在免疫伤害的同时，完美保留穿戴者的生命与行动能力。<br> 穿戴者的形态将会转变为大量的扭动的线稿，生物类型转变为【微型生物】。</p><p>作为【未完成】的作品，观测者，也就是其的穿戴者的态度和划分将会直接影响该护甲的效果。购买时决定，随后不可更改</p><p>若穿戴者认为该护甲【已经完善】，则线稿的画风将会定性。<br> 为了更好的保护成果，护甲会加固线稿以保证自身的稳定。线稿盔甲的护甲防御增加10点。<br> 而更坚韧的线稿能够更充分地吸收所受冲击的能量，为穿戴者提供免疫冲击点数减值的效果，且每次受到的伤害中至多令10点伤害降低一级。</p><p>若穿戴者认为护甲【需被完善】，那么这幅线稿就是你挥洒想法的舞台。<br> 为了更佳的描绘蓝图，你必须更加深切的了解这幅盔甲，哪怕这会令你的头脑难以承担。<br> 现在你可以自主关闭本护甲给予的弱反侦测能力，并能够将线稿描绘成你心所想的模样，转念之间添上了为其他人而看的色彩，乃至模仿的惟妙惟肖，这是一个A级的伪装能力。<br> 并且由于你与护甲的联系加深...其反直觉的运作状态延伸到你的身体各处，也令你本人的原貌难以被查清，你就是这幅线稿！为穿戴者提供免疫A级解析的效果。并且你可以用线稿缝补自己缺失的部分，再提供类似于四肢立即再生的效果。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',11)])])}const m=a(o,[["render",d]]);export{f as __pageData,m as default};
